1	\chapter{The Jacobian as an abelian variety}
2	\label{chap:Jacobian}
3	
4	Let $C$ be a smooth proper curve over $k$ in the sense of Chapter \ref{chap:Genus}, with genus $g = g(C)$.
5	
6	The Picard scheme machinery underlying the construction of $\Jac(C)$ — in particular the relative Picard functor (Definition~\ref{def:Pic_functor}) and its bundled representability theorem (Theorem~\ref{thm:Pic_representable}) — is set up in Chapter~\ref{chap:Picard_Functor}. This chapter consumes those declarations to define the Jacobian and prove the four abelian-variety instances.
7	
8	\section{The Jacobian}
9	
10	\begin{definition}[Jacobian]
11	  \label{def:Jacobian}
12	  \lean{AlgebraicGeometry.Jacobian}
13	  \leanok
14	  \uses{thm:Pic_representable}
15	  The \emph{Jacobian} of $C$ is the abelian variety
16	  \[
17	    \Jac(C) \;=\; \Pic^0_{C/k},
18	  \]
19	  the connected component of the identity of the Picard scheme $\Pic_{C/k}$ representing the relative Picard functor (Definition~\ref{def:Pic_functor}, Theorem~\ref{thm:Pic_representable}). It is viewed as an object of $\textrm{Over}(\Spec k)$.
20	\end{definition}
21	
22	\section{Group scheme structure and abelian-variety properties}
23	
24	\begin{theorem}[Group object structure]
25	  \label{thm:Jacobian_grpObj}
26	  \lean{AlgebraicGeometry.Jacobian.instGrpObj}
27	  \leanok
28	  \uses{def:Jacobian}
29	  $\Jac(C)$ carries a canonical group-object structure in $\textrm{Over}(\Spec k)$, induced from tensor product of line bundles on $C$.
30	\end{theorem}
31	
32	\begin{theorem}[Smoothness and dimension]
33	  \label{thm:Jacobian_smooth_genus}
34	  \lean{AlgebraicGeometry.Jacobian.smoothOfRelativeDimension_genus}
35	  \leanok
36	  \uses{def:Jacobian, def:genus}
37	  $\Jac(C) \to \Spec k$ is smooth of relative dimension $g(C)$.
38	\end{theorem}
39	
40	\begin{theorem}[Properness]
41	  \label{thm:Jacobian_proper}
42	  \lean{AlgebraicGeometry.Jacobian.instIsProper}
43	  \leanok
44	  \uses{def:Jacobian}
45	  $\Jac(C) \to \Spec k$ is proper.
46	\end{theorem}
47	
48	\begin{theorem}[Geometric irreducibility]
49	  \label{thm:Jacobian_geomIrred}
50	  \lean{AlgebraicGeometry.Jacobian.instGeometricallyIrreducible}
51	  \leanok
52	  \uses{def:Jacobian}
53	  $\Jac(C) \to \Spec k$ is geometrically irreducible.
54	\end{theorem}
55	
56	\noindent All four properties are part of the conclusion of Theorem~\ref{thm:Pic_representable}: once $\Pic^0_{C/k}$ is constructed as an abelian scheme of dimension $g(C)$, smoothness, properness and geometric irreducibility hold by construction. The dimension formula in Theorem~\ref{thm:Jacobian_smooth_genus} additionally needs the Phase~A identification of $g(C) = \dim_k H^1(C, \mathcal O_C)$ with the dimension of the tangent space at the identity of $\Pic^0_{C/k}$ (Riemann--Roch / Serre duality).
57	
58	\subsection{Sanity check in low genus}
59	
60	\begin{itemize}
61	  \item $g = 0$: Then $\Pic^0_{C/k} = \Spec k$, the trivial group scheme; $\Jac(\mathbb P^1_k) = \Spec k$ is smooth of relative dimension $0 = g$. The terminal object of $\textrm{Over}(\Spec k)$ already carries \lstinline{GrpObj} via \lstinline{instTensorUnit}.
62	  \item $g = 1$: Then $\Jac(C) \cong C$ once a $k$-rational point on $C$ is fixed; $C$ is itself an abelian variety.
63	  \item $g \ge 2$: $\Jac(C)$ is a non-trivial $g$-dimensional abelian variety, never isomorphic to $C$ as a scheme.
64	\end{itemize}
65	
66	\section{Mathlib gap}
67	
68	The Picard scheme is absent from Mathlib b80f227. Mathlib has only \lstinline{CommRing.Pic R} (the Picard group of a commutative ring) and the abstract \lstinline{GrpObj} machinery. Constructing \lstinline{Jacobian C} therefore requires building, inside this project, the Picard scheme machinery of Chapter~\ref{chap:Picard_Functor}:
69	
70	\begin{itemize}
71	  \item the line-bundle / Picard-group API on a single scheme — Chapter~\ref{chap:Picard_LineBundle} (closed iter-003 under documented first-approximation);
72	  \item the relative Picard functor (Definition~\ref{def:Pic_functor}) — Chapter~\ref{chap:Picard_Functor} (scaffolded iter-004, definition assigned to iter-005 prover);
73	  \item étale sheafification of group-valued functors on $\mathrm{Sch}/k$ — iter-006+;
74	  \item representability for the curve case (Theorem~\ref{thm:Pic_representable}) — FGA-level, deferred indefinitely;
75	  \item the connected-component-of-identity construction for group schemes locally of finite type — iter-006+.
76	\end{itemize}
77	
78	These are mapped to Phase C of \texttt{STRATEGY.md}.
79	
80	\subsection{Status note}
81	
82	The four \lstinline{Jacobian.lean} sorries (\lstinline{Jacobian}, \lstinline{instGrpObj}, \lstinline{instIsProper}, \lstinline{instGeometricallyIrreducible}, plus \lstinline{smoothOfRelativeDimension_genus} which additionally depends on Phase~A) all reduce to Theorem~\ref{thm:Pic_representable}. They are \emph{not} assigned to any prover until that theorem is honestly closed (which is gated on multiple Mathlib chapters: étale sheafification, Hilbert / Quot schemes, Riemann--Roch). Iter-005 will not attack them.
