1	\chapter{The Abel--Jacobi map}
2	\label{chap:AbelJacobi}
3	
4	Let $C$ be a smooth proper curve over $k$ as in Chapter \ref{chap:Genus}, and let $\Jac(C)$ be its Jacobian (Definition \ref{def:Jacobian}).
5	
6	\section{Definition}
7	
8	\begin{definition}[Abel--Jacobi map]
9	  \label{def:ofCurve}
10	  \lean{AlgebraicGeometry.Jacobian.ofCurve}
11	  \leanok
12	  \uses{def:Jacobian}
13	  Given a $k$-rational point $P\colon \Spec k \to C$ — equivalently, a morphism $P\colon \mathbf 1 \to C$ in $\textrm{Over}(\Spec k)$ — the \emph{Abel--Jacobi map} is the $k$-morphism
14	  \[
15	    \alpha_P\colon C \;\longrightarrow\; \Jac(C),\qquad Q \;\longmapsto\; [\mathcal O_C(Q - P)].
16	  \]
17	  Functorially, it is the morphism in $\textrm{Over}(\Spec k)$ induced by the line bundle $\mathcal O_{C \times C}(\Delta - p_1^* P)$ on $C \times C$ via the universal property of $\Pic^0_{C/k}$.
18	\end{definition}
19	
20	\section{Pointed property}
21	
22	\begin{lemma}[$\alpha_P$ sends $P$ to $0$]
23	  \label{lem:comp_ofCurve}
24	  \lean{AlgebraicGeometry.Jacobian.comp_ofCurve}
25	  \leanok
26	  \uses{def:ofCurve}
27	  $P \;\circ\; \alpha_P \;=\; \eta\bigl[\Jac(C)\bigr]$, where $\eta[\Jac(C)]$ is the identity element of the group scheme $\Jac(C)$.
28	\end{lemma}
29	
30	\begin{proof}
31	  \uses{def:ofCurve}
32	  \leanok
33	  At the level of $k$-points: $\alpha_P(P) = [\mathcal O_C(P - P)] = [\mathcal O_C] = 0$. Globally: by construction, $\alpha_P$ is the morphism classifying the line bundle $\mathcal O_{C \times C}(\Delta - p_1^* P)$; restricting to the section $(P, \mathrm{id})$ gives the trivial line bundle, hence the zero point of $\Pic^0$.
34	\end{proof}
35	
36	\section{Universal (Albanese) property}
37	
38	\begin{theorem}[Albanese property of the Jacobian]
39	  \label{thm:exists_unique_ofCurve_comp}
40	  \lean{AlgebraicGeometry.Jacobian.exists_unique_ofCurve_comp}
41	  \leanok
42	  \uses{def:ofCurve, lem:comp_ofCurve}
43	  Let $A$ be an abelian variety over $k$ — i.e.\ $A \in \textrm{Over}(\Spec k)$ with \lstinline{[Smooth A.hom] [IsProper A.hom] [GrpObj A] [GeometricallyIrreducible A.hom]}. For every pointed morphism $f\colon C \to A$ with $f \circ P = \eta[A]$, there exists a unique group-scheme morphism $g\colon \Jac(C) \to A$ such that $f = g \circ \alpha_P$.
44	  \[
45	  \begin{array}{ccc}
46	    C & \stackrel{f}{\longrightarrow} & A \\
47	    {\scriptstyle\alpha_P} \downarrow & \nearrow {\scriptstyle\exists ! g} & \\
48	    \Jac(C) & &
49	  \end{array}
50	  \]
51	\end{theorem}
52	
53	\begin{proof}
54	  \uses{thm:Pic_representable, thm:GrpObj_eq_of_eqOnOpen}
55	  \leanok
56	  \emph{Existence.} The map $f\colon C \to A$ pointed at $P$ is classified, via the Picard-functoriality of $A$, by a line bundle on $C \times A^\vee$ (where $A^\vee$ is the dual abelian variety), normalised so that its restriction along $\{P\}\times A^\vee$ is trivial. By the universal property of $\Pic^0_{C/k}$, this line bundle yields a $k$-morphism $A^\vee \to \Pic^0_{C/k} = \Jac(C)$; dualising back gives $g\colon \Jac(C) \to A$ with $g \circ \alpha_P = f$.
57	
58	  \emph{Uniqueness.} If $g_1, g_2\colon \Jac(C) \to A$ both satisfy $g_i \circ \alpha_P = f$, then $g_1 - g_2\colon \Jac(C) \to A$ vanishes on the image of $\alpha_P$. The image of $\alpha_P$ generates $\Jac(C)$ as a group scheme (a standard fact: the Abel--Jacobi morphism is generically finite onto its image and the symmetric power $C^{(g)}$ surjects onto $\Jac(C)$). Combined with the rigidity theorem for morphisms between abelian varieties (Theorem~\ref{thm:GrpObj_eq_of_eqOnOpen}, the Lean-side scheme-level form of Mumford, \emph{Abelian Varieties}, §4 Theorem 1), this forces $g_1 = g_2$.
59	\end{proof}
60	
61	\section{Mathlib gap}
62	
63	The Albanese property requires:
64	\begin{itemize}
65	  \item the rigidity theorem for morphisms between abelian varieties (Mumford §4) — \emph{not} in Mathlib, but provable from \lstinline{Mathlib/AlgebraicGeometry/Group/Abelian.lean} plus the rigidity lemma for proper morphisms over an irreducible base;
66	  \item generation of $\Jac(C)$ by the image of $\alpha_P$ — requires symmetric powers of curves and the surjectivity $C^{(g)} \twoheadrightarrow \Jac(C)$;
67	  \item dual abelian varieties and biduality — currently absent.
68	\end{itemize}
69	
70	These are mapped to Phase E of \texttt{STRATEGY.md}.
71	
72	\subsection{Discovery objective for this iteration}
73	
74	The prover should:
75	\begin{enumerate}
76	  \item Confirm that none of \lstinline{ofCurve}, \lstinline{comp_ofCurve}, \lstinline{exists_unique_ofCurve_comp} can be filled without first defining \lstinline{Jacobian C} (Chapter \ref{chap:Jacobian}).
77	  \item Document in \lstinline{task_results/AbelJacobi.md} which of the three sorries would become provable from a working \lstinline{Jacobian} via what specific helper lemmas (e.g.\ \enquote{rigidity for morphisms of abelian varieties} as a standalone declaration).
78	  \item \textbf{Do not} introduce a placeholder \lstinline{ofCurve} (such as the constant map to the identity) — this would make \lstinline{exists_unique_ofCurve_comp} false in genus $\ge 1$.
79	\end{enumerate}
