\chapter{The Jacobian as an abelian variety}
\label{chap:Jacobian}

Let $C$ be a smooth proper curve over $k$ in the sense of Chapter~\ref{chap:Genus}, with genus $g = g(C)$.

Because the Picard-scheme machinery (Chapter~\ref{chap:Picard_Functor}) is blocked at the level of \lstinline{MonoidalCategory X.Modules} and the full FGA representability theorem, this chapter builds the Jacobian by an alternative ad-hoc route: the Albanese functor on smooth proper curves.

\section{The Albanese construction}

For a smooth proper curve $C$ over $k$, the Albanese variety is the universal abelian variety receiving a morphism from $C$.  Over an algebraically closed field this is classically identified with the connected component of the identity of the Picard scheme, but we construct it directly from symmetric powers.

\subsection{Symmetric powers and the Abel--Jacobi map}

Let $C^{(g)} = \operatorname{Sym}^g(C)$ be the $g$\textsuperscript{th} symmetric power of $C$ (the quotient of $C^g$ by the action of the symmetric group $S_g$).  It is a smooth proper scheme over $k$ of dimension $g$.  Fix a $k$-rational point $P_0 \in C(k)$.  The map
\[
  \sigma \colon C^{(g)} \longrightarrow \Pic^g_{C/k}, \qquad
  \sum_{i=1}^g [P_i] \longmapsto \mathcal O_C\bigl(\textstyle\sum_{i=1}^g P_i - g P_0\bigr)
\]
is surjective and birational onto its image; its fibres are projective spaces (Brill--Noether--Riemann--Roch).  Choosing $P_0$ gives a translation isomorphism $\Pic^g_{C/k} \xrightarrow{\;\sim\;} \Pic^0_{C/k}$, and the Stein factorisation of $\sigma$ yields the Jacobian as the connected component of the identity.

In the Lean formalisation we do not have general symmetric powers of schemes (or quotients by finite group actions) in Mathlib.  We therefore take a more direct approach: we define the Jacobian as the Albanese object of $C$ inside the category of smooth proper group schemes over $k$, using the universal property and the known dimension formula.

\begin{definition}[Jacobian]
  \label{def:Jacobian}
  \lean{AlgebraicGeometry.Jacobian}
  \leanok
  \uses{def:genus}
  The \emph{Jacobian} of $C$ is the abelian variety $\Jac(C)$ over $k$ obtained as the Albanese object of $C$: a smooth proper geometrically irreducible group scheme over $k$ of dimension $g(C)$ equipped with a universal morphism $C \to \Jac(C)$.  It is viewed as an object of $\textrm{Over}(\Spec k)$.
\end{definition}

\section{Group scheme structure and abelian-variety properties}

\begin{theorem}[Group object structure]
  \label{thm:Jacobian_grpObj}
  \lean{AlgebraicGeometry.Jacobian.instGrpObj}
  \leanok
  \uses{def:Jacobian}
  $\Jac(C)$ carries a canonical group-object structure in $\textrm{Over}(\Spec k)$, induced by the Albanese universal property and the cogroup structure of $C$ in the category of pointed curves.
\end{theorem}

\begin{theorem}[Smoothness and dimension]
  \label{thm:Jacobian_smooth_genus}
  \lean{AlgebraicGeometry.Jacobian.smoothOfRelativeDimension_genus}
  \leanok
  \uses{def:Jacobian, def:genus}
  $\Jac(C) \to \Spec k$ is smooth of relative dimension $g(C)$.
\end{theorem}

\begin{theorem}[Properness]
  \label{thm:Jacobian_proper}
  \lean{AlgebraicGeometry.Jacobian.instIsProper}
  \leanok
  \uses{def:Jacobian}
  $\Jac(C) \to \Spec k$ is proper.
\end{theorem}

\begin{theorem}[Geometric irreducibility]
  \label{thm:Jacobian_geomIrred}
  \lean{AlgebraicGeometry.Jacobian.instGeometricallyIrreducible}
  \leanok
  \uses{def:Jacobian}
  $\Jac(C) \to \Spec k$ is geometrically irreducible.
\end{theorem}

\noindent All four properties are part of the Albanese construction.  Smoothness and dimension follow from the deformation-theoretic identification of the tangent space at the identity with $H^1(C, \mathcal O_C)$ (Phase~A, Chapter~\ref{chap:Cohomology_StructureSheafAb}).  Properness and geometric irreducibility descend from the corresponding properties of $C$ because the Albanese map is surjective with connected fibres.

\subsection{Sanity check in low genus}

\begin{itemize}
  \item $g = 0$: Then $\Jac(C) = \Spec k$, the trivial group scheme; $\Jac(\mathbb P^1_k) = \Spec k$ is smooth of relative dimension $0 = g$.  The terminal object of $\textrm{Over}(\Spec k)$ already carries \lstinline{GrpObj} via \lstinline{instTensorUnit}.
  \item $g = 1$: Then $\Jac(C) \cong C$ once a $k$-rational point on $C$ is fixed; $C$ is itself an abelian variety.
  \item $g \ge 2$: $\Jac(C)$ is a non-trivial $g$-dimensional abelian variety, never isomorphic to $C$ as a scheme.
\end{itemize}

\section{Implementation route in Lean}

Because the full Picard-scheme representability theorem is not available in Mathlib, the formal construction proceeds in two layers:

\begin{enumerate}
  \item \textbf{Layer I -- direct definition.}  Define \lstinline{Jacobian C} as an object of \lstinline{Over (Spec (.of k))} carrying the four instances above.  In the first instance the underlying scheme can be taken to be the terminal object \lstinline{⊤_ (Over (Spec (.of k)))} when the genus is $0$, and for higher genus it is built from an ad-hoc quotient of a suitable symmetric-power-like functor.  Since Mathlib lacks general quotients of schemes by finite group actions, we instead rely on the Albanese universal property: \lstinline{Jacobian C} is declared as the representing object of the Albanese functor for $C$.

  \item \textbf{Layer II -- Abel--Jacobi compatibility.}  Chapter~\ref{chap:AbelJacobi} introduces the Abel--Jacobi morphism $C \to \Jac(C)$ and shows that it is universal among morphisms from $C$ to abelian varieties.  This is the content of the three protected sorries in \lstinline{AbelJacobi.lean}.
\end{enumerate}

\noindent The five protected sorries in \lstinline{Jacobian.lean} (\lstinline{Jacobian}, \lstinline{instGrpObj}, \lstinline{smoothOfRelativeDimension_genus}, \lstinline{instIsProper}, \lstinline{instGeometricallyIrreducible}) and the three in \lstinline{AbelJacobi.lean} (\lstinline{ofCurve}, \lstinline{comp_ofCurve}, \lstinline{exists_unique_ofCurve_comp}) are now in active scope for the prover.  They are assigned to the Phase~C parallel track of \texttt{STRATEGY.md}.
